head.b:skin:
/*==========================================================
                    CSS FRAMEWORK
==========================================================*/

/*----------------------------------------------------------
01. ROOT VARIABLES
----------------------------------------------------------*/

:root{

/* Brand Colors */

--primary:#0d6efd;
--primary-dark:#0b5ed7;
--secondary:#ff6b00;

--success:#198754;
--danger:#dc3545;
--warning:#ffc107;
--info:#0dcaf0;

/* Background */

--body-bg:#f5f7fb;
--card-bg:#ffffff;

/* Text */

--text:#222222;
--text-light:#666666;
--heading:#111111;

/* Border */

--border:#e5e7eb;

/* Radius */

--radius-xs:4px;
--radius-sm:6px;
--radius:10px;
--radius-lg:16px;

/* Shadow */

--shadow-sm:0 2px 6px rgba(0,0,0,.06);
--shadow:0 8px 25px rgba(0,0,0,.08);
--shadow-lg:0 15px 40px rgba(0,0,0,.12);

/* Container */

--container:1280px;

/* Header */

--header-height:72px;

/* Transition */

--transition:.30s ease;

/* Font */

--font:
Arial,
Helvetica,
sans-serif;

}

/*----------------------------------------------------------
02. CSS RESET
----------------------------------------------------------*/

*,
*::before,
*::after{

margin:0;
padding:0;
box-sizing:border-box;

}

html{

scroll-behavior:smooth;

}

body{

background:var(--body-bg);

font-family:var(--font);

font-size:16px;

line-height:1.7;

color:var(--text);

overflow-x:hidden;

text-rendering:optimizeLegibility;

-webkit-font-smoothing:antialiased;

}

img{

display:block;

max-width:100%;

height:auto;

}

a{

text-decoration:none;

color:inherit;

transition:var(--transition);

}

ul,
ol{

list-style:none;

}

button,
input,
textarea,
select{

font:inherit;

outline:none;

border:none;

background:none;

}

table{

border-collapse:collapse;

width:100%;

}

/*----------------------------------------------------------
03. LAYOUT
----------------------------------------------------------*/

.container{

width:100%;

max-width:var(--container);

margin:auto;

padding:0 18px;

}

.section{

padding:60px 0;

}

.hidden{

display:none;

}

.clear{

clear:both;

}

/*----------------------------------------------------------
04. TYPOGRAPHY
----------------------------------------------------------*/

h1,
h2,
h3,
h4,
h5,
h6{

font-weight:700;

color:var(--heading);

line-height:1.3;

margin-bottom:16px;

}

h1{

font-size:42px;

}

h2{

font-size:34px;

}

h3{

font-size:28px;

}

h4{

font-size:22px;

}

h5{

font-size:18px;

}

h6{

font-size:16px;

}

p{

margin-bottom:16px;

color:var(--text-light);

}

strong{

font-weight:700;

}

small{

font-size:13px;

}

/*----------------------------------------------------------
05. LINKS
----------------------------------------------------------*/

a:hover{

color:var(--primary);

}

/*----------------------------------------------------------
END OF PART 1B
----------------------------------------------------------*/
